import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(start_pos, end_pos, speed):
        return np.linalg.norm(end_pos - start_pos) / speed

    def calculate_penalty(early_time, late_time, current_time):
        if current_time < early_time:
            return early_time - current_time
        elif current_time > late_time:
            return current_time - late_time
        else:
            return 0

    min_time = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        penalty = calculate_penalty(time_windows[i][0], time_windows[i][1], current_time + travel_time)
        total_time = current_time + travel_time + penalty

        if total_time < min_time:
            min_time = total_time
            best_node = i

    return best_node
